import React, { useState } from 'react';
import './ComingSoon.css';

const ComingSoon = () => {
  const [email, setEmail] = useState('');

  const handleNotify = () => {
    if (email) {
      alert(`Thank you! We will notify you at ${email}`);
      setEmail('');
    } else {
      alert('Please enter your email address');
    }
  };

  return (
    <div className="coming-soon-page">

      {/* HERO SECTION */}
      <div className="hero-section">
        <div className="overlay"></div>

        <div className="hero-content">
          <div className="logo">
            <span className="logo-icon">🚘</span>
            <span className="brand-name">Car24</span>
          </div>

          <h1>
            Premium Rental Cars <br />
            <span>Ready When You Are</span>
          </h1>

          <p className="tagline">
            Affordable • Flexible • Unlimited Mileage • 24/7 Pickup
          </p>

          <div className="notify-form">
            <input
              type="email"
              placeholder="Enter your email for early access"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
            <button onClick={handleNotify}>Get Early Access</button>
          </div>

          <p className="coming-text">Launching Soon 🚀</p>
        </div>
      </div>

      {/* FEATURES SECTION */}
      <div className="features-section">
        <div className="feature-card">
          <span>⚡</span>
          <h3>Electric & Hybrid Fleet</h3>
          <p>Drive smart with eco-friendly vehicles.</p>
        </div>

        <div className="feature-card">
          <span>🔑</span>
          <h3>Keyless Pickup</h3>
          <p>Contactless 24/7 self service access.</p>
        </div>

        <div className="feature-card">
          <span>🛡️</span>
          <h3>Fully Insured</h3>
          <p>Premium protection on every ride.</p>
        </div>

        <div className="feature-card">
          <span>🗺️</span>
          <h3>Unlimited Mileage</h3>
          <p>Travel anywhere without restrictions.</p>
        </div>
      </div>

      {/* FOOTER */}
      <div className="footer">
        Powered by <strong>Stackenzo</strong>
      </div>

    </div>
  );
};

export default ComingSoon;
